import{_ as e,Q as i,S as t,a5 as a}from"./framework-291a1352.js";const p="/assets/1-59adb590.jpeg",o="/assets/2-a8c08743.jpeg",s="/assets/3-d6b5fca4.jpeg",c="/assets/4-b66376fe.jpeg",n="/assets/5-88fdedfb.jpeg",r={},d=a('<h1 id="登高望远-夜幕降临" tabindex="-1"><a class="header-anchor" href="#登高望远-夜幕降临" aria-hidden="true">#</a> 登高望远，夜幕降临</h1><blockquote><p>写于 <code>2013年8月1日</code></p></blockquote><p>夜幕即将降临，骑上单车，穿过那片田野。</p><p>来到山脚下，惊动雏鸟，鸟儿藏匿。</p><p>回望田野，阡陌纵横。</p><p>登上山顶，凉风袭来。</p><p>遥望夕阳，静观晚霞。</p><p>环顾四周，村落人家，炊烟缕缕。</p><p>万里群山，千姿百态。</p><p>山谷松木，郁郁葱葱。</p><p>忽见蛇行，匆匆击掌，惊起白鹤数只。</p><p>远处湖泊，听到车声，定睛一看，原是高速路。</p><p>天空鸟儿飞过，叫声凄凉，归栖息地。</p><p>急忙下山，虫声四起，远处灯火闪烁，骑车归家，一路蚊子嗡嗡作响。</p><p>夜幕登高，颇多惬意。</p><p><code>2018年10月5日重新登山 发朋友圈附图</code><img src="'+p+'" alt="稻田" loading="lazy"></p><figure><img src="'+o+'" alt="阡陌纵横" tabindex="0" loading="lazy"><figcaption>阡陌纵横</figcaption></figure><figure><img src="'+s+'" alt="四面环山" tabindex="0" loading="lazy"><figcaption>四面环山</figcaption></figure><figure><img src="'+c+'" alt="夕阳西下" tabindex="0" loading="lazy"><figcaption>夕阳西下</figcaption></figure><figure><img src="'+n+'" alt="夕阳西下2" tabindex="0" loading="lazy"><figcaption>夕阳西下2</figcaption></figure>',20),g=[d];function f(l,_){return i(),t("div",null,g)}const u=e(r,[["render",f],["__file","index.html.vue"]]);export{u as default};
